code.C:
#include <stdio.h>
int main() {
    double A, B;
    char operator;
    scanf("%lf", &A);
    scanf("%lf", &B);
    scanf(" %c", &operator);
    switch (operator) {
        case '+': printf("%.6f\n", A + B); break;
        case '-': printf("%.6f\n", A - B); break;
        case '*': printf("%.6f\n", A * B); break;
        case '/': printf("%.6f\n", A / B); break;
    }
    return 0;
}

